SELECT ?play ?playLabel ?premiere
WHERE {
  ?film wdt:P1552 ?play ;
        wdt:P31 wd:Q11424 .
  ?play wdt:P50 wd:Q179663 ;
        wdt:P31 wd:Q1482055 ;
        wdt:P571 ?premiere .
  ?play rdfs:label ?playLabel .
  FILTER (LANG(?playLabel) = "en")
}
ORDER BY ?premiere

